import agentops
import anthropic
import json

client = anthropic.Anthropic()

tools = [
    {
        "name": "write_file",
        "description": "Write content to a file. Allowed paths: /tmp/ or /workspace/ only.",
        "input_schema": {
            "type": "object",
            "properties": {
                "path": {"type": "string"},
                "content": {"type": "string"},
            },
            "required": ["path", "content"],
        },
    }
]

def execute_tool_with_audit(tool_name: str, tool_input: dict, session) -> str:
    """Execute a tool and emit an AgentOps span for the call."""
    if tool_name == "write_file":
        path = tool_input["path"]
        allowed = path.startswith("/tmp/") or path.startswith("/workspace/")

        # Guardrail check logged as a span event regardless of outcome
        session.record(agentops.Event(
            event_type="tool_call",
            params={"tool": tool_name, "path": path, "allowed": allowed},
        ))

        if not allowed:
            raise PermissionError(
                f"write_file blocked: path {path!r} is outside allowed directories"
            )
        with open(path, "w") as f:
            f.write(tool_input["content"])
        return f"Wrote {len(tool_input['content'])} bytes to {path}"

    raise ValueError(f"Unknown tool: {tool_name}")


def run_tool_agent(task: str) -> str:
    agentops.init(api_key="your-key")
    with agentops.start_session(tags=["tool-agent"]) as session:
        messages = [{"role": "user", "content": task}]

        while True:
            response = client.messages.create(
                model="claude-sonnet-4-5",
                max_tokens=1024,
                tools=tools,
                messages=messages,
            )
            messages.append({"role": "assistant", "content": response.content})

            if response.stop_reason == "end_turn":
                for block in response.content:
                    if hasattr(block, "text"):
                        return block.text

            if response.stop_reason == "tool_use":
                results = []
                for block in response.content:
                    if block.type == "tool_use":
                        try:
                            result = execute_tool_with_audit(block.name, block.input, session)
                            results.append({
                                "type": "tool_result",
                                "tool_use_id": block.id,
                                "content": result,
                            })
                        except PermissionError as e:
                            results.append({
                                "type": "tool_result",
                                "tool_use_id": block.id,
                                "content": f"ERROR: {e}",
                                "is_error": True,
                            })
                messages.append({"role": "user", "content": results})

        return "Agent loop exhausted"

import agentops
import anthropic
import json

client = anthropic.Anthropic()

def search_clauses(contract_id: str, clause_type: str) -> list[dict]:
    """Return clauses matching clause_type from a contract (simulated)."""
    # In production: vector search over embedded contract text
    return [
        {
            "contract_id": contract_id,
            "text": f"Party A shall indemnify Party B... liability capped at $500,000.",
            "page": 3,
        }
    ]

tools = [
    {
        "name": "search_clauses",
        "description": "Search a contract for clauses of a specified type.",
        "input_schema": {
            "type": "object",
            "properties": {
                "contract_id": {"type": "string"},
                "clause_type": {
                    "type": "string",
                    "description": "e.g. 'indemnification', 'limitation of liability'",
                },
            },
            "required": ["contract_id", "clause_type"],
        },
    }
]

def run_legal_agent(task: str, contract_ids: list[str]) -> str:
    agentops.init(api_key="your-key", default_tags=["legal", "prod"])

    with agentops.start_session(tags=["contract-analysis"]) as session:
        session.record(agentops.Event(
            "task_start",
            params={"task": task, "contracts": contract_ids},
        ))

        messages = [
            {
                "role": "user",
                "content": (
                    f"Task: {task}\n"
                    f"Available contracts: {', '.join(contract_ids)}\n"
                    "Use search_clauses to retrieve relevant clauses, then analyze them."
                ),
            }
        ]

        tool_call_count = 0
        while True:
            response = client.messages.create(
                model="claude-sonnet-4-5",
                max_tokens=2048,
                tools=tools,
                messages=messages,
            )
            messages.append({"role": "assistant", "content": response.content})

            if response.stop_reason == "end_turn":
                for block in response.content:
                    if hasattr(block, "text"):
                        session.record(agentops.Event(
                            "task_end",
                            params={"tool_calls": tool_call_count, "outcome": "success"},
                        ))
                        return block.text

            if response.stop_reason == "tool_use":
                results = []
                for block in response.content:
                    if block.type == "tool_use":
                        tool_call_count += 1
                        session.record(agentops.Event(
                            "tool_call",
                            params={
                                "tool": block.name,
                                "input": block.input,
                                "call_num": tool_call_count,
                            },
                        ))
                        if block.name == "search_clauses":
                            clauses = search_clauses(**block.input)
                            results.append({
                                "type": "tool_result",
                                "tool_use_id": block.id,
                                "content": json.dumps(clauses),
                            })
                messages.append({"role": "user", "content": results})

        return "Agent loop exhausted without conclusion"


result = run_legal_agent(
    task="Find indemnification clauses and flag those capping liability below $1M",
    contract_ids=["contract-A", "contract-B", "contract-C"],
)
print(result)
